INSERT INTO public.testimonials (customer_name, city, content, rating, sort_order, is_active) VALUES
('Carla Mendes', 'São Paulo - SP', 'Recebi meu pallet super rápido. Veio cheio de eletrônicos e produtos novos, paguei muito menos do que custaria na loja. Recomendo!', 5, 1, true),
('Rafael Souza', 'Belo Horizonte - MG', 'Já é o terceiro pallet que compro. Sempre vem coisa boa, revendi tudo e tirei mais que o triplo do investimento.', 5, 2, true),
('Juliana Alves', 'Curitiba - PR', 'Atendimento muito atencioso no WhatsApp. Tirei todas as dúvidas antes de comprar e o produto chegou direitinho.', 5, 3, true),
('Marcos Pereira', 'Rio de Janeiro - RJ', 'Comprei o pallet Trader e veio tênis, fones e roupa nova com etiqueta. Vale demais a pena!', 5, 4, true),
('Patrícia Lima', 'Fortaleza - CE', 'Tinha medo de ser furada, mas é tudo real. Embalagem caprichada e nota fiscal certinha.', 5, 5, true),
('Diego Ramos', 'Porto Alegre - RS', 'Melhor investimento que fiz pra começar a revender online. Em uma semana já paguei o pallet.', 5, 6, true);